def load_snapshot(path):
    if not os.path.exists(path):
        return []
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)

def should_ignore(path: str) -> bool:
    parts = set(path.split(os.sep))

    if any(part in IGNORE_DIRS for part in parts):
        return True

    if any(path.endswith(ext) for ext in IGNORE_EXTENSIONS):
        return True

    return False

def detect_language(path: str) -> str:
    if path.endswith(".py"):
        return "python"
    if path.endswith(".js"):
        return "javascript"
    if path.endswith(".ts"):
        return "typescript"
    if path.endswith(".c"):
        return "c"
    if path.endswith(".h"):
        return "c"
    if path.endswith(".md"):
        return "markdown"
    if path.endswith(".json"):
        return "json"
    return "unknown"

def scan_directory(root="."):
    results = []

    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if d not in IGNORE_DIRS]

        for file in filenames:
            full_path = os.path.join(dirpath, file)

            if should_ignore(full_path):
                continue

            try:
                with open(full_path, "r", encoding="utf-8") as f:
                    content = f.read()
            except Exception:
                continue

            is_python = full_path.endswith(".py")

            if is_python:
                imports = extract_imports(full_path, content)
                functions = extract_functions(content)
                functions.sort(key=lambda x: x["lineno"])
            else:
                imports = []
                functions = []

            results.append({
                "path": normalize(full_path),
                "size": len(content),
                "modified_at": os.path.getmtime(full_path),
                "language": detect_language(full_path),
                "imports": imports,
                "functions": functions
            })

    return results

def extract_imports(path, source):
    """
    Returns structured imports:
    [
        {"type": "...", "target": "..."}
    ]
    """
    imports = []

    try:
        tree = ast.parse(source)
    except Exception:
        return imports

    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                imports.append({
                    "type": "local_or_external",
                    "target": alias.name.split(".")[0]
                })

        elif isinstance(node, ast.ImportFrom):
            if node.module:
                imports.append({
                    "type": "local_or_external",
                    "target": node.module.split(".")[0]
                })

    return imports

def _get_source_segment(source_lines, node):
    """Extract function body from source using line numbers"""
    start = node.lineno - 1
    end = getattr(node, "end_lineno", node.lineno)
    return "\n".join(source_lines[start:end])

def extract_functions(source: str):
    functions = []

    try:
        tree = ast.parse(source)
        source_lines = source.splitlines()
    except Exception:
        return functions

    for node in tree.body:
        if isinstance(node, ast.FunctionDef):

            body = _get_source_segment(source_lines, node)

            functions.append({
                "name": node.name,
                "lineno": node.lineno,
                "end_lineno": getattr(node, "end_lineno", node.lineno),
                "args": [arg.arg for arg in node.args.args],

                # NEW FIELDS (3.2 core)
                "body": body,
                "hash": _hash(body)
            })

    return functions

def compute_file_map(snapshot):
    """
    Converts snapshot list into dict:
    path -> file entry
    """
    return {f["path"]: f for f in snapshot}

def diff_functions(old_funcs, new_funcs):
    """
    Function-level diff using stable hashes.
    Returns added / removed / modified.
    """

    old_by_hash = {f["hash"]: f for f in old_funcs}
    new_by_hash = {f["hash"]: f for f in new_funcs}

    old_hashes = set(old_by_hash.keys())
    new_hashes = set(new_by_hash.keys())

    added = [new_by_hash[h] for h in new_hashes - old_hashes]
    removed = [old_by_hash[h] for h in old_hashes - new_hashes]

    # MODIFIED = same function name, different hash
    modified = []

    old_by_name = {}
    new_by_name = {}

    for f in old_funcs:
        old_by_name.setdefault(f["name"], []).append(f)

    for f in new_funcs:
        new_by_name.setdefault(f["name"], []).append(f)

    common_names = set(old_by_name.keys()) & set(new_by_name.keys())

    for name in common_names:
        old_set = {f["hash"] for f in old_by_name[name]}
        new_set = {f["hash"] for f in new_by_name[name]}

        if old_set != new_set:
            modified.append({
                "function": name,
                "old": old_by_name[name],
                "new": new_by_name[name]
            })

    return {
        "added": added,
        "removed": removed,
        "modified": modified
    }
